        let _TEMP3 /* SDAI.LOGICAL */ = _TEMP2 <= SDAI.FORCE_OPTIONAL(SDAI.INTEGER(1))
        return _TEMP3
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        NAME: tLABEL, 
        DESCRIPTION: tTEXT? , 
        CHOSEN_METHOD: eACTION_METHOD.PRef
      ) {

        self._name = NAME
        self._description = DESCRIPTION
        self._chosen_method = CHOSEN_METHOD

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( NAME: original._name, DESCRIPTION: original._description, CHOSEN_METHOD: original._chosen_method )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 3
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: tLABEL.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]NAME for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverOptionalParameter(as: tTEXT.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]DESCRIPTION for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverRequiredParameter(as: eACTION_METHOD.PRef.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]CHOSEN_METHOD for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( NAME: p0, DESCRIPTION: p1, CHOSEN_METHOD: p2 )
      }
    }
  }
